import { Component, OnDestroy } from '@angular/core';

@Component({
  selector: 'app-root',
  standalone: true,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  count = 0;
  step = 1;
  autoRunning = false;
  private intervalId: number | null = null;

  get isZero(): boolean {
    return this.count === 0;
  }

  inc(): void {
    this.count += this.step;
  }

  dec(): void {
    this.count = Math.max(0, this.count - this.step);
  }

  setStep(value: string): void {
    this.step = Number(value);
  }

  stopAuto(): void {
    if (this.intervalId !== null) {
      window.clearInterval(this.intervalId);
      this.intervalId = null;
    }
    this.autoRunning = false;
  }

  toggleAuto(): void {
    if (this.intervalId !== null) {
      this.stopAuto();
      return;
    }
    this.autoRunning = true;
    this.inc();
    this.intervalId = window.setInterval(() => this.inc(), 500);
  }

  reset(): void {
    this.stopAuto();
    this.count = 0;
  }

  onCounterKeydown(event: KeyboardEvent): void {
    const target = event.target as HTMLElement;
    if (['BUTTON', 'SELECT', 'INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
    if (event.key === 'ArrowUp') this.inc();
    else if (event.key === 'ArrowDown') this.dec();
    else if (event.key === 'Home') this.reset();
    else return;
    event.preventDefault();
  }

  ngOnDestroy(): void {
    this.stopAuto();
  }
}
